INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('9a9426c7-dafc-545f-b409-3487655ca1a2', '2a29f581-ded3-4a51-89ec-e8ceb4ebb8fd', 'My dream is to visit ___ and see the famous Hollywood movies.', '我的夢想是去美國旅遊並看那些著名的好萊塢電影。', 'America', 'England', 'Japan', 'France', '專有名詞，指美國或美洲。', '看到 Hollywood (好萊塢) 就聯想到 America (美國)。', '2026-07-06 14:01:13', '2026-07-06 14:01:13'),
('d63019f6-aad6-5a56-a2b9-e798a6a88636', '82f91108-38f0-4b1a-b73e-fbaacd6dc557', '___ hope that my advice will be helpful to you during your study abroad program.', '我希望我的建議對你在海外留學期間會有幫助。', 'I', 'He', 'She', 'They', 'I 是第一人稱單數主格代名詞。', 'I 就像是指著自己的手指。', '2026-07-05 09:58:22', '2026-07-05 09:58:22'),
('e4d64b7e-45aa-5885-88ce-ae2fcf44b436', '861d9958-7e46-4f38-9f52-c2239d3f5aad', 'The ___ of Confucius provide profound wisdom for people seeking moral guidance in modern times.', '孔子的語錄為尋求現代道德指引的人們提供了深邃的智慧。', 'analects', 'biographies', 'prophecies', 'journals', 'ana- (聚集/收集) + lect (收集/讀) → 意指被收集起來的話語或語錄。', '聯想 lect (收集/讀) 與 lecture (演講) 的關聯，analects 就是將演講中的精華「收集」起來的語錄。', '2026-07-06 21:00:45', '2026-07-06 21:00:45'),
('ce8344c5-d49b-54d7-a90b-0cc5a0478f72', '863f960c-9dea-4632-a9cb-3487b5c50eab', 'We ___ very happy.', '我們非常開心。', 'are', 'like', 'want', 'need', 'be 動詞，用於複數主詞表示「是」。', 'We → are', '2026-07-05 11:32:46', '2026-07-05 11:32:46'),
('867d64b6-8552-5cf7-a3b0-afc302b0ef86', '0ed1ef08-585a-44cc-9a00-3e665e426b57', 'Due to the rising cost of fuel, many people are considering replacing their ___ with electric bicycles.', '由於燃料成本上升，許多人正考慮用電動自行車來取代他們的 ___。', 'automobile', 'aircraft', 'submarine', 'locomotive', 'auto (自動) + mobile (可移動的) → 自動移動的機器。', 'auto (自動) → automatic (自動的); mobile (移動) → mobile phone (行動電話) → 自動移動的東西就是汽車。', '2026-07-07 03:51:05', '2026-07-07 03:51:05'),
('ba8af791-8426-533a-bb62-9c4e9c51459e', 'c7a82848-efc5-492c-b7a0-e0183e09da73', 'There is a ___ dog in the park.', '公園裡有一隻大狗。', 'big', 'red', 'fast', 'kind', '基本單字，描述體型。', 'Big 聯想一個巨大的東西。', '2026-07-07 03:37:09', '2026-07-07 03:37:09'),
('6c1f6e9d-1f4c-5909-8a0e-79ca8cec594a', '67249bcb-5c14-4651-a1c5-491505ad4aae', 'Please put the orange juice into the glass ___.', '請把柳橙汁裝進玻璃瓶裡。', 'bottle', 'cup', 'box', 'spoon', 'bottle 為名詞，意指裝液體的瓶子。', '想像一個圓圓的瓶子 (bottle) 裝滿了飲料。', '2026-07-07 05:27:07', '2026-07-07 05:27:07'),
('96e2c7db-735c-5d5a-9218-bbbb8141ecb6', '06015372-66ed-4e4e-894f-ade889deb2af', 'The street is very ___ in the morning.', '這條街道在早上非常繁忙。', 'busy', 'quiet', 'clean', 'small', 'adj. 繁忙的', '繁忙的街道 → busy street。', '2026-07-07 09:03:39', '2026-07-07 09:03:39'),
('23a27213-81e2-5bcf-a382-0c49990f8b16', '735b0ab4-7942-483e-bf74-df364748969f', 'The ___ of the basketball team is very tall and strong.', '這支籃球隊的隊長非常高大且強壯。', 'captain', 'doctor', 'teacher', 'farmer', 'cap- 源自拉丁語，有「頭」的意思，引申為領導者或首領。', '想像船長 (captain) 站在船頭 (cap) 指揮全船的人。', '2026-07-07 02:22:18', '2026-07-07 02:22:18'),
('a55a8ed7-ca8d-52ea-883c-55e413134652', '88a090df-09e8-4836-9bda-a1e004875405', 'Please look at the ___ on the wall to see what time it is.', '請看牆上的鐘，看看現在幾點。', 'clock', 'book', 'chair', 'window', 'clock 為名詞，指用來顯示時間的儀器（鐘）。', 'clock 讀音接近「可樂」，想像喝著可樂時要看「鐘」的時間。', '2026-07-07 04:42:44', '2026-07-07 04:42:44'),
('52b035d6-a926-58fa-b23c-999ec8d87d0a', '12cde2bd-ae5c-4e25-8e04-91ffac271468', 'We walked along the ___ to enjoy the beautiful sea view.', '我們沿著海岸散步，欣賞美麗的海景。', 'coast', 'forest', 'mountain', 'river', 'coast 為名詞，指陸地與海洋交界的「海岸」。', '想像你要「靠」在海邊看風景，coast 的發音可以聯想為「靠」在岸邊。', '2026-07-07 04:55:22', '2026-07-07 04:55:22'),
('b07168a3-7690-53cd-8074-172c89b32492', 'f5c4e464-2f21-468c-8bb9-e8111d97c097', 'You must pay a small ___ to enter the park.', '你必須支付一小筆費用才能進入公園。', 'fee', 'gift', 'song', 'rule', 'fee 為名詞，指為了獲得某種服務或權利而支付的費用。', 'fee 讀音像「非」，可以記成「非」付錢不可 → 費用。', '2026-07-07 05:21:12', '2026-07-07 05:21:12');
